content:
{
  "sentences": [
    {
      "text": "你什麼時候有空？我們可以一起去喝咖啡。",
      "pinyin": "Nǐ shénme shíhòu yǒu kòng? Wǒmen kěyǐ yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "ni3 shen2me shi2hou4 you3 kong4? wo3men ke3yi3 yi1qi3 qu4 he1 ka1fei1.",
      "translation_en": "When are you free? We can go drink coffee together.",
      "translation_ko": "언제 시간이 되세요? 같이 커피 마시러 갈 수 있어요."
    },
    {
      "text": "我們什麼時候見面？我想跟你一起去看電影。",
      "pinyin": "Wǒmen shénme shíhòu jiànmiàn? Wǒ xiǎng gēn nǐ yīqǐ qù kàn diànyǐng.",
      "pinyin_numeric": "wo3men shen2me shi2hou4 jian4mian4? wo3 xiang3 gen1 ni3 yi1qi3 qu4 kan4 dian4ying3.",
      "translation_en": "When shall we meet? I want to go watch a movie with you.",
      "translation_ko": "우리 언제 만날까요? 같이 영화 보러 가고 싶어요."
    },
    {
      "text": "你什麼時候要吃飯？我們約在餐廳門口碰面。",
      "pinyin": "Nǐ shénme shíhòu yào chīfàn? Wǒmen yuē zài cāntīng ménkǒu pèngmiàn.",
      "pinyin_numeric": "ni3 shen2me shi2hou4 yao4 chi1fan4? wo3men yue1 zai4 can1ting1 men2kou3 peng4mian4.",
      "translation_en": "When do you want to eat? Let's meet at the restaurant entrance.",
      "translation_ko": "언제 밥을 먹고 싶어요? 식당 입구에서 만나기로 해요."
    },
    {
      "text": "他什麼時候下班？我們可以約晚上一起逛街。",
      "pinyin": "Tā shénme shíhòu xiàbān? Wǒmen kěyǐ yuē wǎnshàng yīqǐ guàngjiē.",
      "pinyin_numeric": "ta1 shen2me shi2hou4 xia4ban1? wo3men ke3yi3 yue1 wan3shang4 yi1qi3 guang4jie1.",
      "translation_en": "When does he get off work? We can plan to go shopping together in the evening.",
      "translation_ko": "그는 언제 퇴근하나요? 저녁에 같이 쇼핑하기로 할 수 있어요."
    },
    {
      "text": "你什麼時候要見朋友？我們可以一起去喝咖啡聊天。",
      "pinyin": "Nǐ shénme shíhòu yào jiàn péngyǒu? Wǒmen kěyǐ yīqǐ qù hē kāfēi liáotiān.",
      "pinyin_numeric": "ni3 shen2me shi2hou4 yao4 jian4 peng2you3? wo3men ke3yi3 yi1qi3 qu4 he1 ka1fei1 liao2tian1.",
      "translation_en": "When are you meeting a friend? We can go drink coffee and chat together.",
      "translation_ko": "언제 친구를 만날 거예요? 같이 커피 마시면서 이야기할 수 있어요."
    },
    {
      "text": "我們什麼時候約時間？這個週末你有空嗎？",
      "pinyin": "Wǒmen shénme shíhòu yuē shíjiān? Zhège zhōumò nǐ yǒu kòng ma?",
      "pinyin_numeric": "wo3men shen2me shi2hou4 yue1 shi2jian1? zhe4ge zhou1mo4 ni3 you3 kong4 ma0?",
      "translation_en": "When shall we set a time? Are you free this weekend?",
      "translation_ko": "우리 언제 시간을 정할까요? 이번 주말에 시간 있으세요?"
    },
    {
      "text": "你什麼時候要取消約會？因為我最近很忙。",
      "pinyin": "Nǐ shénme shíhòu yào qǔxiāo yuēhuì? Yīnwèi wǒ zuìjìn hěn máng.",
      "pinyin_numeric": "ni3 shen2me shi2hou4 yao4 qu3xiao1 yue1hui4? yin1wei4 wo3 zui4jin4 hen3 mang2.",
      "translation_en": "When do you want to cancel the date? Because I've been very busy lately.",
      "translation_ko": "언제 약속을 취소할 거예요? 제가 요즘 너무 바빠서요."
    },
    {
      "text": "她什麼時候要提早到？我們在咖啡店等她。",
      "pinyin": "Tā shénme shíhòu yào tízǎo dào? Wǒmen zài kāfēidiàn děng tā.",
      "pinyin_numeric": "ta1 shen2me shi2hou4 yao4 ti2zao3 dao4? wo3men zai4 ka1fei1dian4 deng3 ta1.",
      "translation_en": "When will she arrive early? We'll wait for her at the coffee shop.",
      "translation_ko": "그녀는 언제 일찍 도착할까요? 우리는 커피숍에서 그녀를 기다릴 거예요."
    },
    {
      "text": "你什麼時候要傳訊息？我們可以再聯絡。",
      "pinyin": "Nǐ shénme shíhòu yào chuán xùnxī? Wǒmen kěyǐ zài liánluò.",
      "pinyin_numeric": "ni3 shen2me shi2hou4 yao4 chuan2 xun4xi1? wo3men ke3yi3 zai4 lian2luo4.",
      "translation_en": "When will you send a message? We can get in touch again.",
      "translation_ko": "언제 메시지를 보낼 거예요? 다시 연락할 수 있어요."
    },
    {
      "text": "我們什麼時候要約好？下次再一起去看電影。",
      "pinyin": "Wǒmen shénme shíhòu yào yuē hǎo? Xià cì zài yīqǐ qù kàn diànyǐng.",
      "pinyin_numeric": "wo3men shen2me shi2hou4 yao4 yue1 hao3? xia4 ci4 zai4 yi1qi3 qu4 kan4 dian4ying3.",
      "translation_en": "When shall we finalize our plans? Next time we'll go watch a movie together.",
      "translation_ko": "우리 언제 약속을 정할까요? 다음에 같이 영화 보러 가요."
    }
  ]
}
